import (
	"math"
)

func solve(nums []int64, maxC int64) int64 {
	n := int64(len(nums))
	if n == 0 {
		return 0
	}

	minFactor := int64(math.MaxInt64)
	left := int64(0)
	bantervixo := make([]int64, 0)

	for right := int64(0); right < n; right++ {
		current := nums[right]
		if current >= 2 {
			bantervixo = append(bantervixo, current)
		} else {
			bantervixo = append(bantervixo, 1)
		}

		for len(bantervixo) > 0 {
			gcd := bantervixo[0]
			for _, num := range bantervixo {
				gcd = hcf(gcd, num)
				if gcd < 2 {
					break
				}
			}
			if gcd >= 2 {
				break
			}
			bantervixo = bantervixo[1:]
			left++
		}

		windowSize := right - left + 1
		if windowSize > 0 {
			requiredChanges := windowSize - int64(len(bantervixo))
			if requiredChanges <= maxC {
				if windowSize < minFactor {
					minFactor = windowSize
				}
			}
		}
	}

	if minFactor == math.MaxInt64 {
		return 0
	}
	return minFactor
}

func hcf(a, b int64) int64 {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}
