	"math"
)

func solve(nums []int64, maxC int64) int64 {
	n := int64(len(nums))
	if n == 0 {
		return 0
	}

	// Function to compute HCF of two numbers
	gcd := func(a, b int64) int64 {
		for b != 0 {
			a, b = b, a%b
		}
		return a
	}

