	prefix := make([][]int64, n)
	for i := range prefix {
		prefix[i] = make([]int64, 20) // 20 is enough for log2(1e5)
	}

	for i := int64(0); i < n; i++ {
		prefix[i][0] = nums[i]
	}

	for j := int64(1); (1 << j) <= n; j++ {
		for i := int64(0); i+(1<<j)-1 < n; i++ {
			prefix[i][j] = gcd(prefix[i][j-1], prefix[i+(1<<(j-1))][j-1])
		}
	}

